using System;

class Program
{
    static void Main(string[] args)
    {
        PrintInfo("Ali");
        PrintInfo("Ali", 20);
    }

    static void PrintInfo(string name)
    {
        Console.WriteLine($"Ad: {name}");
    }

    static void PrintInfo(string name, int age)
    {
        Console.WriteLine($"Ad: {name}, Yaş: {age}");
    }
}
// Output:
// Ad: Ali
// Ad: Ali, Yaş: 20

using System;

class Program
{
    static void Main(string[] args)
    {
        Add(5, 3);
        Add(5.5, 3.2);
    }

    static void Add(int a, int b)
    {
        Console.WriteLine($"Tam ədədlərin cəmi: {a + b}");
    }

    static void Add(double a, double b)
    {
        Console.WriteLine($"Kəsr ədədlərin cəmi: {a + b}");
    }
}
// Output:
// Tam ədədlərin cəmi: 8
// Kəsr ədədlərin cəmi: 8.7

using System;

class Program
{
    static void Main(string[] args)
    {
        int intResult = Calculate(5);
        double doubleResult = Calculate(5.0);
        Console.WriteLine($"Tam ədəd kvadratı: {intResult}");
        Console.WriteLine($"Kəsr ədəd kvadratı: {doubleResult}");
    }

    static int Calculate(int number)
    {
        return number * number;
    }

    static double Calculate(double number)
    {
        return number * number;
    }
}
// Output:
// Tam ədəd kvadratı: 25
